import { create } from 'zustand';
import { Medicine, OrderItem } from '@/types';

export interface DeliveryAddress {
  id: string;
  fullName: string;
  mobile: string;
  houseUnit: string;
  street: string;
  barangay: string;
  city: string;
  province: string;
  zipCode: string;
  notes?: string;
  isDefault?: boolean;
}

export interface PharmacyState {
  cart: OrderItem[];
  prescriptionFile: File | null;
  prescriptionUrl: string | null;
  selectedAddressId: string | null;
  savedAddresses: DeliveryAddress[];
  selectedPaymentMethod: string;
  addToCart: (medicine: Medicine) => void;
  removeFromCart: (medicineId: string) => void;
  updateQuantity: (medicineId: string, quantity: number) => void;
  clearCart: () => void;
  setPrescription: (file: File | null, url: string | null) => void;
  setSelectedAddress: (id: string) => void;
  addAddress: (address: Omit<DeliveryAddress, 'id'>) => void;
  setPaymentMethod: (method: string) => void;
  cartTotal: () => number;
  cartCount: () => number;
  hasRxItems: () => boolean;
}

const defaultAddresses: DeliveryAddress[] = [
  {
    id: 'addr-1',
    fullName: 'Maria Santos',
    mobile: '+63 917 123 4567',
    houseUnit: '123',
    street: 'Makati Avenue',
    barangay: 'Bel-Air',
    city: 'Makati City',
    province: 'Metro Manila',
    zipCode: '1209',
    isDefault: true,
  },
  {
    id: 'addr-2',
    fullName: 'Maria Santos',
    mobile: '+63 917 123 4567',
    houseUnit: 'Unit 5B',
    street: 'Ayala Avenue',
    barangay: 'Salcedo Village',
    city: 'Makati City',
    province: 'Metro Manila',
    zipCode: '1227',
    notes: 'Near the park, blue gate',
  },
];

export const usePharmacyStore = create<PharmacyState>((set, get) => ({
  cart: [],
  prescriptionFile: null,
  prescriptionUrl: null,
  selectedAddressId: 'addr-1',
  savedAddresses: defaultAddresses,
  selectedPaymentMethod: 'cod',

  addToCart: (medicine) => {
    set((state) => {
      const existing = state.cart.find((i) => i.medicine.id === medicine.id);
      if (existing) {
        return {
          cart: state.cart.map((i) =>
            i.medicine.id === medicine.id ? { ...i, quantity: i.quantity + 1 } : i
          ),
        };
      }
      return { cart: [...state.cart, { medicine, quantity: 1 }] };
    });
  },

  removeFromCart: (medicineId) =>
    set((state) => ({ cart: state.cart.filter((i) => i.medicine.id !== medicineId) })),

  updateQuantity: (medicineId, quantity) =>
    set((state) => ({
      cart:
        quantity <= 0
          ? state.cart.filter((i) => i.medicine.id !== medicineId)
          : state.cart.map((i) =>
              i.medicine.id === medicineId ? { ...i, quantity } : i
            ),
    })),

  clearCart: () => set({ cart: [], prescriptionFile: null, prescriptionUrl: null }),

  setPrescription: (file, url) => set({ prescriptionFile: file, prescriptionUrl: url }),

  setSelectedAddress: (id) => set({ selectedAddressId: id }),

  addAddress: (address) => {
    const id = `addr-${Date.now()}`;
    set((state) => ({
      savedAddresses: [...state.savedAddresses, { ...address, id }],
      selectedAddressId: id,
    }));
  },

  setPaymentMethod: (method) => set({ selectedPaymentMethod: method }),

  cartTotal: () => get().cart.reduce((sum, i) => sum + i.medicine.price * i.quantity, 0),

  cartCount: () => get().cart.reduce((sum, i) => sum + i.quantity, 0),

  hasRxItems: () => get().cart.some((i) => i.medicine.requiresPrescription),
}));
